// world.js — map load (top-level await), box(), colliders, shotBlockers, medkits, weapon spawns
import * as THREE from 'three';
import { S } from './state.js';
import './scene.js'; // populates S.scene before the box()/floor calls below add to it
import { WEAPONS } from './weapons.js';

// ---------- map (v3 top-down dust2 — generated by tools/gen_map.py) ----------
const SAND = 0xc9b074;
export const worldMeshes = [];
export const colliders = []; // {minX..maxZ}
function box(x, z, w, h, d, color, y = 0) {
  const m = new THREE.Mesh(new THREE.BoxGeometry(w, h, d), new THREE.MeshLambertMaterial({ color }));
  m.position.set(x, y + h / 2, z);
  S.scene.add(m); worldMeshes.push(m);
  if (h > 0.3) colliders.push({ minX: x - w/2, maxX: x + w/2, minY: y, maxY: y + h, minZ: z - d/2, maxZ: z + d/2 });
  return m;
}
{
  const f = new THREE.Mesh(new THREE.BoxGeometry(152, 1, 152), new THREE.MeshLambertMaterial({ color: SAND }));
  f.position.y = -0.5; S.scene.add(f); worldMeshes.push(f);
}
let MAP;
try {
  MAP = await fetch('map.json').then(r => { if (!r.ok) throw new Error(r.status); return r.json(); });
} catch (e) {
  document.querySelector('#join .sub').textContent = 'FAILED TO LOAD MAP — REFRESH PAGE';
  throw e;
}
for (const b of MAP.boxes) box(b.x, b.z, b.w, b.h, b.d, b.c, b.y || 0);

// ---------- 2D shot occlusion (top-down: height never matters, only footprint) ----------
// Bullets travel on the XZ plane. A box blocks a shot iff it is chest-high cover/wall
// (h >= 1.2) AND it is not a walkable plateau (#c2a96a). Soft cover (h<1.2), stairs/marks
// and the elevation plateaus themselves stay transparent — so a player on the +1.5 T plateau
// and one on the ground hit each other freely. Same flat model as Brawl Stars.
const PLAT_COLOR = '#c2a96a';
export const shotBlockers = MAP.boxes
  .filter(b => b.h >= 1.2 && b.c !== PLAT_COLOR)
  .map(b => ({ minX: b.x - b.w / 2, maxX: b.x + b.w / 2, minZ: b.z - b.d / 2, maxZ: b.z + b.d / 2 }));

// ---------- medkits ----------
const MEDKITS = MAP.medkits; // [x, z] — same source as server
export const medkitMeshes = [];
export function buildMedkits(states) {
  if (medkitMeshes.length) { // reconnect: just sync visibility
    states.forEach((s, i) => { if (medkitMeshes[i]) medkitMeshes[i].visible = s !== 0; });
    return;
  }
  MEDKITS.forEach(([x, z, y], i) => {
    const g = new THREE.Group();
    const base = new THREE.Mesh(new THREE.BoxGeometry(0.9, 0.4, 0.9), new THREE.MeshLambertMaterial({ color: 0xf2f2f2 }));
    base.position.y = 0.55;
    const c1 = new THREE.Mesh(new THREE.BoxGeometry(0.62, 0.18, 0.2), new THREE.MeshLambertMaterial({ color: 0xd1342f }));
    const c2 = new THREE.Mesh(new THREE.BoxGeometry(0.2, 0.18, 0.62), new THREE.MeshLambertMaterial({ color: 0xd1342f }));
    c1.position.y = 0.84; c2.position.y = 0.84;
    g.add(base, c1, c2);
    g.position.set(x, y || 0, z);
    g.userData.baseY = y || 0;
    g.visible = states[i] !== 0;
    S.scene.add(g);
    medkitMeshes.push(g);
  });
}

// ---------- weapon spawns ----------
const WEAPON_SPAWNS = MAP.weaponSpawns || []; // [{x,z,w}] — same source as server
export const weaponMeshes = [];
export function buildWeaponSpawns(states) {
  if (weaponMeshes.length) { // reconnect: just sync visibility
    states.forEach((s, i) => { if (weaponMeshes[i]) weaponMeshes[i].visible = s !== 0; });
    return;
  }
  WEAPON_SPAWNS.forEach((s, i) => {
    const g = new THREE.Group();
    const base = new THREE.Mesh(new THREE.BoxGeometry(0.7, 0.35, 0.7), new THREE.MeshLambertMaterial({ color: 0x3a3528 }));
    base.position.y = 0.5;
    const accent = new THREE.Mesh(new THREE.BoxGeometry(0.5, 0.16, 0.5), new THREE.MeshLambertMaterial({ color: WEAPONS[s.w].color }));
    accent.position.y = 0.78;
    g.add(base, accent);
    g.position.set(s.x, 0, s.z);
    g.userData.baseY = 0;
    g.visible = states[i] !== 0;
    S.scene.add(g);
    weaponMeshes.push(g);
  });
}

// ---------- armor pickups ----------
const ARMOR_SPAWNS = MAP.armor || []; // [x, z, y] — same source as server
export const armorMeshes = [];
export function buildArmor(states) {
  if (armorMeshes.length) { // reconnect: just sync visibility
    states.forEach((s, i) => { if (armorMeshes[i]) armorMeshes[i].visible = s !== 0; });
    return;
  }
  ARMOR_SPAWNS.forEach(([x, z, y], i) => {
    const g = new THREE.Group();
    const base = new THREE.Mesh(new THREE.BoxGeometry(0.85, 0.4, 0.85), new THREE.MeshLambertMaterial({ color: 0x4a5568 }));
    base.position.y = 0.55;
    const plate = new THREE.Mesh(new THREE.BoxGeometry(0.5, 0.5, 0.16), new THREE.MeshLambertMaterial({ color: 0x6a8fb5 }));
    plate.position.y = 0.85; plate.rotation.x = Math.PI / 2;
    g.add(base, plate);
    g.position.set(x, y || 0, z);
    g.userData.baseY = y || 0;
    g.visible = states[i] !== 0;
    S.scene.add(g);
    armorMeshes.push(g);
  });
}

// ---------- boost pickups ----------
const BOOST_SPAWNS = MAP.boosts || []; // [x, z, y] — same source as server
export const boostMeshes = [];
export function buildBoosts(states) {
  if (boostMeshes.length) { // reconnect: just sync visibility
    states.forEach((s, i) => { if (boostMeshes[i]) boostMeshes[i].visible = s !== 0; });
    return;
  }
  BOOST_SPAWNS.forEach(([x, z, y], i) => {
    const g = new THREE.Group();
    const base = new THREE.Mesh(new THREE.BoxGeometry(0.7, 0.4, 0.7), new THREE.MeshLambertMaterial({ color: 0xe6c33a }));
    base.position.y = 0.55;
    const bolt = new THREE.Mesh(new THREE.BoxGeometry(0.2, 0.6, 0.2), new THREE.MeshLambertMaterial({ color: 0xfff2a0 }));
    bolt.position.y = 0.9; bolt.rotation.z = Math.PI / 8;
    g.add(base, bolt);
    g.position.set(x, y || 0, z);
    g.userData.baseY = y || 0;
    g.visible = states[i] !== 0;
    S.scene.add(g);
    boostMeshes.push(g);
  });
}
